example.basic_udf:
from pyspark.sql.functions import udf
from pyspark.sql.types import StringType, IntegerType, DoubleType

# Define Python function:
def classify_salary(salary: float) -> str:
    if salary is None:
        return 'Unknown'
    elif salary >= 90000:
        return 'Senior'
    elif salary >= 70000:
        return 'Mid'
    else:
        return 'Junior'

# Register as UDF:
classify_udf = udf(classify_salary, StringType())

# Use in DataFrame:
df.withColumn('level', classify_udf(col('salary'))).show()

# Decorator syntax:
@udf(returnType=StringType())
def parse_email_domain(email: str) -> str:
    if email is None:
        return None
    return email.split('@')[-1]

df.withColumn('domain', parse_email_domain(col('email'))).show()

# Register for SQL:
spark.udf.register('classify_salary_sql', classify_salary, StringType())
spark.sql("SELECT name, classify_salary_sql(salary) as level FROM employees").show()

example.scalar_pandas_udf:
from pyspark.sql.functions import pandas_udf
from pyspark.sql.types import DoubleType, StringType
import pandas as pd
import numpy as np

# Scalar Pandas UDF: Series in → Series out (same length)
@pandas_udf(DoubleType())
def log_transform(s: pd.Series) -> pd.Series:
    return np.log1p(s)  # log(1 + x) — vectorized on entire Series!

df.withColumn('log_salary', log_transform(col('salary'))).show()

# Complex string processing:
@pandas_udf(StringType())
def clean_name(names: pd.Series) -> pd.Series:
    return names.str.strip().str.title().str.replace(r'[^a-zA-Z ]', '', regex=True)

df.withColumn('clean_name', clean_name(col('name'))).show()

example.grouped_agg_udf:
# Grouped Aggregate: Series in → scalar out
@pandas_udf(DoubleType())
def weighted_avg(values: pd.Series, weights: pd.Series) -> float:
    return (values * weights).sum() / weights.sum()

df.groupBy('dept').agg(
    weighted_avg(col('salary'), col('tenure')).alias('weighted_salary')
).show()
